// Calculate 24 hours ago in ISO format
const now = new Date();
const twentyFourHoursAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);
return [{ json: { cutoff: twentyFourHoursAgo.toISOString() } }];

const response = $input.first().json;
const drafts = Array.isArray(response.body) ? response.body : (Array.isArray(response) ? response : []);

if (drafts.length === 0) {
  return [{ json: { hasIssues: false, message: 'No recent AI drafts to check', checkedCount: 0, issues: [] } }];
}

const localTerms = ['wisconsin', 'dane county', 'zone 5a', 'zone 5b', 'zone 4b', 'silt loam', 'madison', 'clay', 'glacial', 'driftless', 'lake mendota', 'lake monona', 'yahara'];
const ctaTerms = ['608', 'tgyardcare', 'totalguard', 'total guard'];

const issues = [];

for (const draft of drafts) {
  const draftIssues = [];
  const content = draft.content || '';

  // Strip HTML for text analysis
  const textOnly = content.replace(/<[^>]*>/g, ' ').replace(/&[a-z]+;/g, ' ').replace(/\s+/g, ' ').trim();
  const textLower = textOnly.toLowerCase();
  const wordCount = textOnly.split(/\s+/).filter(w => w.length > 0).length;

  // Check 1: Word count >= 800
  if (wordCount < 800) {
    draftIssues.push(`Word count too low: ${wordCount} (minimum 800)`);
  }

  // Check 2: No placeholder text [bracket content]
  const placeholders = content.match(/\[[^\]]*(?:insert|TBD|placeholder|TODO|your|CITY|COMPANY)[^\]]*\]/gi);
  if (placeholders && placeholders.length > 0) {
    draftIssues.push(`Contains placeholder text: ${placeholders.join(', ')}`);
  }

  // Check 3: 3+ H2 headings
  const h2Count = (content.match(/<h2[^>]*>/gi) || []).length;
  if (h2Count < 3) {
    draftIssues.push(`Only ${h2Count} H2 headings (minimum 3)`);
  }

  // Check 4: 2+ local references
  let localRefCount = 0;
  for (const term of localTerms) {
    if (textLower.includes(term)) localRefCount++;
  }
  if (localRefCount < 2) {
    draftIssues.push(`Only ${localRefCount} local references found (minimum 2). Checked: Wisconsin, Dane County, Zone 5a, silt loam, Madison, etc.`);
  }

  // Check 5: Has CTA (608 phone or tgyardcare)
  let hasCTA = false;
  for (const term of ctaTerms) {
    if (textLower.includes(term)) { hasCTA = true; break; }
  }
  if (!hasCTA) {
    draftIssues.push('Missing CTA: no 608 phone number or tgyardcare.com reference found');
  }

  if (draftIssues.length > 0) {
    issues.push({
      id: draft.id,
      title: draft.title || 'Untitled',
      slug: draft.slug || 'no-slug',
      wordCount,
      h2Count,
      localRefCount,
      hasCTA,
      problems: draftIssues
    });
  }
}

return [{ json: {
  hasIssues: issues.length > 0,
  checkedCount: drafts.length,
  issueCount: issues.length,
  passedCount: drafts.length - issues.length,
  issues
} }];
